from django.db.models import Prefetch
from django.utils import timezone
from datetime import timedelta

# SOLUTION 1: select_related for ForeignKey/OneToOne — single JOIN
def get_orders_optimized():
    return Order.objects.select_related(
        "user",
        "shipping_address"  # Also ForeignKey
    ).all()
    # Now order.user.email and order.shipping_address are free — no extra queries


# SOLUTION 2: prefetch_related for ManyToMany / reverse FK
def get_orders_with_items():
    return Order.objects.prefetch_related("items").all()
    # for order in orders: for item in order.items.all() — no extra queries


# SOLUTION 3: Combined select_related + prefetch_related + nested prefetch
def get_orders_full():
    """Fetch orders with user, address, and all items including their products."""
    return Order.objects.select_related(
        "user",
        "shipping_address"
    ).prefetch_related(
        "items",
        "items__product"  # Nested prefetch: items AND their products in 2 extra queries
    )


# SOLUTION 4: Custom Prefetch for filtered/annotated related objects
def get_users_with_recent_orders():
    """Fetch users with only their recent orders (not all orders)."""
    recent_orders = Prefetch(
        "orders",
        queryset=Order.objects.filter(
            created_at__gte=timezone.now() - timedelta(days=30)
        ).select_related("shipping_address"),
        to_attr="recent_orders"  # Access via user.recent_orders (list, not queryset)
    )
    return User.objects.prefetch_related(recent_orders)


# SOLUTION 5: only/defer for large text/binary fields
def get_articles_list():
    """Fetch article list without loading large content body."""
    return Article.objects.defer("content", "raw_html").all()

def get_article_detail(article_id: int) -> Article:
    """Fetch single article with all fields."""
    return Article.objects.get(pk=article_id)

# selectors.py — all query optimization in one place
from django.db.models import QuerySet, Prefetch

def get_order_list(*, user: User) -> QuerySet[Order]:
    """Return optimized queryset for order list endpoint."""
    return (
        Order.objects
        .filter(user=user)
        .select_related("user", "shipping_address")
        .prefetch_related(
            Prefetch(
                "items",
                queryset=OrderItem.objects.select_related("product"),
            )
        )
        .order_by("-created_at")
    )


# views.py — thin, no ORM optimization here
def order_list_view(request):
    orders = get_order_list(user=request.user)
    ...

from django.db.models import F

# GOOD: bulk_create — 1 INSERT for N items
def create_order_items(*, order: Order, items: list[dict]) -> None:
    order_items = [
        OrderItem(
            order=order,
            product_id=item["product_id"],
            quantity=item["quantity"],
        )
        for item in items
    ]
    OrderItem.objects.bulk_create(order_items, batch_size=500)


# GOOD: F() expression — atomic server-side decrement, 1 UPDATE per product
def decrease_stock(*, items: list[dict]) -> None:
    for item in items:
        Product.objects.filter(pk=item["product_id"]).update(
            stock=F("stock") - item["quantity"]
        )


# BAD: Individual saves — N queries
def create_order_items_bad(*, order: Order, items: list[dict]) -> None:
    for item in items:
        OrderItem.objects.create(  # 1 INSERT per item
            order=order,
            product_id=item["product_id"],
            quantity=item["quantity"],
        )
